namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly object _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new Notification(_nextId++, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new Notification(_nextId++, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new Notification(_nextId++, "New feature available: dark mode.", DateTime.UtcNow.AddMinutes(-2)));
    }

    /// <summary>
    /// Returns all notifications currently available.
    /// </summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>
    /// Returns only notifications with an Id greater than the given value.
    /// </summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally to generate fake data.
    /// </summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "You have a new follower.",
            "Someone commented on your post.",
            "Your build succeeded.",
            "Deployment complete.",
            "Reminder: team standup in 15 min.",
            "New message from Alice.",
            "Server health check passed.",
        };

        lock (_lock)
        {
            var msg = messages[_nextId % messages.Length];
            _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
        }
    }
}

namespace NotificationsApp.Services;

/// <summary>
/// Background service that periodically generates fake notifications
/// so the polling page has new data to discover.
/// </summary>
public class NotificationSimulatorHostedService : BackgroundService
{
    private readonly NotificationService _notificationService;

    public NotificationSimulatorHostedService(NotificationService notificationService)
    {
        _notificationService = notificationService;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(7), stoppingToken);
            _notificationService.SimulateIncoming();
        }
    }
}

@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@using NotificationsApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    /// <summary>
    /// Runs during both prerender AND interactive render.
    /// Loads the initial set of notifications so they appear in the
    /// server-rendered HTML immediately.
    /// </summary>
    protected override void OnInitialized()
    {
        _notifications = NotificationService.GetAll();
        _lastSeenId = _notifications.Count > 0
            ? _notifications.Max(n => n.Id)
            : 0;
    }

    /// <summary>
    /// Called only once per lifecycle stage. During prerender this fires but
    /// OnAfterRender does not, so the polling loop only starts in the
    /// interactive render.
    /// </summary>
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (TaskCanceledException)
            {
                break;
            }

            var newItems = NotificationService.GetSince(_lastSeenId);
            if (newItems.Count > 0)
            {
                _notifications.AddRange(newItems);
                _lastSeenId = newItems.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

